package com.omnischool.service.impl;

import com.omnischool.dto.LoginRequest;
import com.omnischool.dto.LoginResponse;
import com.omnischool.dto.RefreshTokenResponse;
import com.omnischool.dto.UserDTO;
import com.omnischool.entity.User;
import com.omnischool.exception.ResourceNotFoundException;
import com.omnischool.repository.UserRepository;
import com.omnischool.security.JwtTokenProvider;
import com.omnischool.service.AuthService;
import jakarta.transaction.Transactional;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.userdetails.UsernameNotFoundException;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;

@Service
public class AuthServiceImpl implements AuthService {

    private final AuthenticationManager authenticationManager;
    private final JwtTokenProvider tokenProvider;
    private final UserRepository userRepository;

    public AuthServiceImpl(AuthenticationManager authenticationManager,
                           JwtTokenProvider tokenProvider,
                           UserRepository userRepository) {
        this.authenticationManager = authenticationManager;
        this.tokenProvider = tokenProvider;
        this.userRepository = userRepository;
    }

    @Transactional
    @Override
    public LoginResponse login(LoginRequest request) {
        Authentication authentication = authenticationManager.authenticate(
                new UsernamePasswordAuthenticationToken(request.getEmail(), request.getPassword())
        );

        User user = userRepository.findByEmail(request.getEmail())
                .orElseThrow(() -> new UsernameNotFoundException("User not found"));
        user.setLastLogin(LocalDateTime.now());

        String token = tokenProvider.generateAccessToken(authentication);
        String refreshToken = tokenProvider.generateRefreshToken(authentication);

        return LoginResponse.builder()
                .token(token)
                .refreshToken(refreshToken)
                .user(toUserDTO(user))
                .build();
    }

    @Override
    public RefreshTokenResponse refreshToken(String refreshToken) {
        if (!tokenProvider.validateToken(refreshToken)) {
            throw new ResourceNotFoundException("Invalid refresh token");
        }
        String email = tokenProvider.getEmailFromToken(refreshToken);

        // Ensure user still exists and is active.
        User user = userRepository.findByEmail(email)
                .orElseThrow(() -> new ResourceNotFoundException("User not found"));
        if (!Boolean.TRUE.equals(user.getIsActive())) {
            throw new ResourceNotFoundException("User is inactive");
        }

        Authentication authentication = new UsernamePasswordAuthenticationToken(
                email,
                null,
                java.util.List.of(new org.springframework.security.core.authority.SimpleGrantedAuthority("ROLE_" + user.getRole().name()))
        );

        String newAccess = tokenProvider.generateAccessToken(authentication);
        String newRefresh = tokenProvider.generateRefreshToken(authentication);

        return RefreshTokenResponse.builder()
                .token(newAccess)
                .refreshToken(newRefresh)
                .build();
    }

    private static UserDTO toUserDTO(User user) {
        return UserDTO.builder()
                .id(user.getId())
                .email(user.getEmail())
                .firstName(user.getFirstName())
                .lastName(user.getLastName())
                .role(user.getRole())
                .build();
    }
}

package com.omnischool.service.impl;

import com.omnischool.dto.ContactMessageDTO;
import com.omnischool.entity.ContactMessage;
import com.omnischool.enums.ContactMessageStatus;
import com.omnischool.exception.ResourceNotFoundException;
import com.omnischool.repository.ContactMessageRepository;
import com.omnischool.service.ContactMessageService;
import com.omnischool.service.EmailService;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;
import java.util.List;

@Service
public class ContactMessageServiceImpl implements ContactMessageService {

    private final ContactMessageRepository repository;
    private final EmailService emailService;

    public ContactMessageServiceImpl(ContactMessageRepository repository, EmailService emailService) {
        this.repository = repository;
        this.emailService = emailService;
    }

    @Override
    public ContactMessageDTO submit(ContactMessageDTO dto) {
        ContactMessage saved = repository.save(toEntity(dto));
        emailService.sendContactConfirmation(saved);
        return toDto(saved);
    }

    @Override
    public List<ContactMessageDTO> getAll() {
        return repository.findAll().stream().map(ContactMessageServiceImpl::toDto).toList();
    }

    @Override
    public ContactMessageDTO updateStatus(Long id, ContactMessageStatus status) {
        ContactMessage entity = repository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("ContactMessage not found"));
        entity.setStatus(status);
        if (status == ContactMessageStatus.READ) {
            entity.setReadAt(LocalDateTime.now());
        }
        return toDto(repository.save(entity));
    }

    private static ContactMessage toEntity(ContactMessageDTO d) {
        return ContactMessage.builder()
                .id(d.getId())
                .name(d.getName())
                .email(d.getEmail())
                .phone(d.getPhone())
                .subject(d.getSubject())
                .message(d.getMessage())
                .status(d.getStatus())
                .build();
    }

    private static ContactMessageDTO toDto(ContactMessage e) {
        return ContactMessageDTO.builder()
                .id(e.getId())
                .name(e.getName())
                .email(e.getEmail())
                .phone(e.getPhone())
                .subject(e.getSubject())
                .message(e.getMessage())
                .status(e.getStatus())
                .createdAt(e.getCreatedAt())
                .readAt(e.getReadAt())
                .build();
    }
}

package com.omnischool.service.impl;

import com.omnischool.dto.DashboardStatsDTO;
import com.omnischool.dto.DailyTrendDTO;
import com.omnischool.dto.DemoRequestDTO;
import com.omnischool.entity.DemoRequest;
import com.omnischool.enums.DemoStatus;
import com.omnischool.exception.ResourceNotFoundException;
import com.omnischool.repository.DemoRequestRepository;
import com.omnischool.service.DemoRequestService;
import com.omnischool.service.EmailService;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;

import java.time.LocalDate;
import java.time.LocalDateTime;
import java.util.*;

/**
 * Demo requests service implementation.
 */
@Service
public class DemoRequestServiceImpl implements DemoRequestService {

    private final DemoRequestRepository repository;
    private final EmailService emailService;

    public DemoRequestServiceImpl(DemoRequestRepository repository, EmailService emailService) {
        this.repository = repository;
        this.emailService = emailService;
    }

    @Override
    public DemoRequestDTO createDemoRequest(DemoRequestDTO dto) {
        DemoRequest entity = toEntity(dto);
        entity.setId(null);
        entity.setStatus(DemoStatus.PENDING);

        DemoRequest saved = repository.save(entity);

        // Async emails
        emailService.sendDemoRequestConfirmation(saved);
        emailService.sendAdminNotification(saved);

        return toDto(saved);
    }

    @Override
    public Page<DemoRequestDTO> getFilteredRequests(DemoStatus status, String search, Pageable pageable) {
        String normalized = (search == null || search.isBlank()) ? null : search.trim();
        return repository.search(status, normalized, pageable)
                .map(DemoRequestServiceImpl::toDto);
    }

    @Override
    public DemoRequestDTO getById(Long id) {
        DemoRequest entity = repository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("DemoRequest not found"));
        return toDto(entity);
    }

    @Override
    public DemoRequestDTO updateStatus(Long id, DemoStatus status) {
        DemoRequest entity = repository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("DemoRequest not found"));

        DemoStatus old = entity.getStatus();
        entity.setStatus(status);

        if (status == DemoStatus.SCHEDULED) {
            entity.setScheduledAt(LocalDateTime.now());
        }

        DemoRequest saved = repository.save(entity);

        // Notify requester about status update
        emailService.sendDemoStatusUpdateNotification(saved, old, status);

        return toDto(saved);
    }

    @Override
    public void delete(Long id) {
        if (!repository.existsById(id)) {
            throw new ResourceNotFoundException("DemoRequest not found");
        }
        repository.deleteById(id);
    }

    @Override
    public DashboardStatsDTO calculateStats(LocalDate startDate, LocalDate endDate) {
        LocalDateTime start = (startDate == null)
                ? LocalDate.now().minusDays(30).atStartOfDay()
                : startDate.atStartOfDay();
        LocalDateTime end = (endDate == null)
                ? LocalDate.now().plusDays(1).atStartOfDay()
                : endDate.plusDays(1).atStartOfDay();

        List<DemoRequest> range = repository.findByCreatedAtBetween(start, end);

        long total = range.size();
        long pending = range.stream().filter(r -> r.getStatus() == DemoStatus.PENDING).count();
        long completed = range.stream().filter(r -> r.getStatus() == DemoStatus.COMPLETED).count();
        double conversion = total == 0 ? 0.0 : (completed * 100.0) / total;

        Map<DemoStatus, Long> byStatus = new EnumMap<>(DemoStatus.class);
        for (DemoStatus s : DemoStatus.values()) {
            long count = range.stream().filter(r -> r.getStatus() == s).count();
            byStatus.put(s, count);
        }

        Map<LocalDate, List<DemoRequest>> perDay = new HashMap<>();
        for (DemoRequest r : range) {
            if (r.getCreatedAt() == null) continue;
            LocalDate day = r.getCreatedAt().toLocalDate();
            perDay.computeIfAbsent(day, d -> new ArrayList<>()).add(r);
        }

        List<DailyTrendDTO> trends = perDay.entrySet().stream()
                .sorted(Map.Entry.comparingByKey())
                .map(e -> {
                    long req = e.getValue().size();
                    long conv = e.getValue().stream().filter(r -> r.getStatus() == DemoStatus.COMPLETED).count();
                    return DailyTrendDTO.builder()
                            .date(e.getKey())
                            .requests(req)
                            .conversions(conv)
                            .build();
                })
                .toList();

        return DashboardStatsDTO.builder()
                .totalDemoRequests(total)
                .pendingRequests(pending)
                .completedRequests(completed)
                .conversionRate(conversion)
                .dailyTrends(trends)
                .requestsByStatus(byStatus)
                .build();
    }

    // -----------------------
    // Mapping helpers
    // -----------------------

    private static DemoRequestDTO toDto(DemoRequest e) {
        return DemoRequestDTO.builder()
                .id(e.getId())
                .fullName(e.getFullName())
                .email(e.getEmail())
                .phone(e.getPhone())
                .schoolName(e.getSchoolName())
                .schoolType(e.getSchoolType())
                .city(e.getCity())
                .numberOfStudents(e.getNumberOfStudents())
                .level(e.getLevel())
                .currentSystem(e.getCurrentSystem())
                .preferredDate(e.getPreferredDate())
                .preferredTime(e.getPreferredTime())
                .interestedIn(e.getInterestedIn())
                .message(e.getMessage())
                .status(e.getStatus())
                .assignedTo(e.getAssignedTo())
                .createdAt(e.getCreatedAt())
                .updatedAt(e.getUpdatedAt())
                .scheduledAt(e.getScheduledAt())
                .build();
    }

    private static DemoRequest toEntity(DemoRequestDTO d) {
        return DemoRequest.builder()
                .id(d.getId())
                .fullName(d.getFullName())
                .email(d.getEmail())
                .phone(d.getPhone())
                .schoolName(d.getSchoolName())
                .schoolType(d.getSchoolType())
                .city(d.getCity())
                .numberOfStudents(d.getNumberOfStudents())
                .level(d.getLevel())
                .currentSystem(d.getCurrentSystem())
                .preferredDate(d.getPreferredDate())
                .preferredTime(d.getPreferredTime())
                .interestedIn(d.getInterestedIn() == null ? new ArrayList<>() : new ArrayList<>(d.getInterestedIn()))
                .message(d.getMessage())
                .status(d.getStatus())
                .assignedTo(d.getAssignedTo())
                .scheduledAt(d.getScheduledAt())
                .build();
    }
}

package com.omnischool.service.impl;

import com.omnischool.entity.ContactMessage;
import com.omnischool.entity.DemoRequest;
import com.omnischool.enums.DemoStatus;
import com.omnischool.service.EmailService;
import jakarta.mail.MessagingException;
import jakarta.mail.internet.MimeMessage;
import org.springframework.mail.javamail.JavaMailSender;
import org.springframework.mail.javamail.MimeMessageHelper;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;

/**
 * Simple HTML mail sender.
 */
@Service
public class EmailServiceImpl implements EmailService {

    private static final String ADMIN_EMAIL = "admin@omnischool.tn";

    private final JavaMailSender mailSender;

    public EmailServiceImpl(JavaMailSender mailSender) {
        this.mailSender = mailSender;
    }

    @Async
    @Override
    public void sendDemoRequestConfirmation(DemoRequest request) {
        String subject = "OmniSchool | Demo request received";
        String body = """
                <div style='font-family:Arial,sans-serif'>
                  <h2>Thank you, %s</h2>
                  <p>We received your demo request for <b>%s</b>.</p>
                  <p>Our team will contact you shortly.</p>
                  <hr/>
                  <p style='font-size:12px;color:#666'>OmniSchool (Tunisia)</p>
                </div>
                """.formatted(escape(request.getFullName()), escape(request.getSchoolName()));
        safeSend(request.getEmail(), subject, body);
    }

    @Async
    @Override
    public void sendAdminNotification(DemoRequest request) {
        String subject = "OmniSchool | New demo request";
        String body = """
                <div style='font-family:Arial,sans-serif'>
                  <h2>New demo request</h2>
                  <p><b>Name:</b> %s</p>
                  <p><b>Email:</b> %s</p>
                  <p><b>Phone:</b> %s</p>
                  <p><b>School:</b> %s (%s)</p>
                  <p><b>Students:</b> %s</p>
                  <p><b>Message:</b> %s</p>
                </div>
                """.formatted(
                escape(request.getFullName()),
                escape(request.getEmail()),
                escape(request.getPhone()),
                escape(request.getSchoolName()),
                request.getSchoolType() == null ? "" : request.getSchoolType().name(),
                request.getNumberOfStudents() == null ? "" : request.getNumberOfStudents(),
                escape(request.getMessage())
        );
        safeSend(ADMIN_EMAIL, subject, body);
    }

    @Async
    @Override
    public void sendContactConfirmation(ContactMessage message) {
        String subject = "OmniSchool | We received your message";
        String body = """
                <div style='font-family:Arial,sans-serif'>
                  <h2>Thank you, %s</h2>
                  <p>We received your message about: <b>%s</b>.</p>
                  <p>We will reply as soon as possible.</p>
                </div>
                """.formatted(escape(message.getName()), escape(message.getSubject()));
        safeSend(message.getEmail(), subject, body);
    }

    @Async
    @Override
    public void sendDemoStatusUpdateNotification(DemoRequest request, DemoStatus oldStatus, DemoStatus newStatus) {
        String subject = "OmniSchool | Demo request update";
        String body = """
                <div style='font-family:Arial,sans-serif'>
                  <h2>Hello, %s</h2>
                  <p>Your demo request status changed from <b>%s</b> to <b>%s</b>.</p>
                  <p>School: <b>%s</b></p>
                </div>
                """.formatted(
                escape(request.getFullName()),
                oldStatus == null ? "" : oldStatus.name(),
                newStatus == null ? "" : newStatus.name(),
                escape(request.getSchoolName())
        );
        safeSend(request.getEmail(), subject, body);
    }

    private void safeSend(String to, String subject, String htmlBody) {
        try {
            MimeMessage mimeMessage = mailSender.createMimeMessage();
            MimeMessageHelper helper = new MimeMessageHelper(mimeMessage, "UTF-8");
            helper.setTo(to);
            helper.setSubject(subject);
            helper.setText(htmlBody, true);
            mailSender.send(mimeMessage);
        } catch (MessagingException ex) {
            // Intentionally swallow to avoid failing business flow due to mail issues.
        }
    }

    private static String escape(String s) {
        if (s == null) return "";
        return s.replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;");
    }
}

package com.omnischool.model;

import com.omnischool.model.enums.SchoolType;
import com.omnischool.model.enums.SubscriptionPlan;
import jakarta.persistence.*;
import lombok.*;

import java.time.LocalDate;
import java.time.LocalDateTime;

@Entity
@Table(name = "schools")
@Getter
@Setter
@NoArgsConstructor
@AllArgsConstructor
@Builder
public class School {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    private String name;
    private String address;
    private String city;
    private String phone;
    private String email;

    @Enumerated(EnumType.STRING)
    private SchoolType type;

    private Integer totalStudents;
    private Integer totalTeachers;

    @Enumerated(EnumType.STRING)
    private SubscriptionPlan plan;

    private LocalDate subscriptionStartDate;
    private LocalDate subscriptionEndDate;

    private Boolean isActive;

    private LocalDateTime createdAt;

    @PrePersist
    protected void onCreate() {
        createdAt = LocalDateTime.now();
        if (isActive == null) isActive = true;
    }
}

