                    lineHeight: '1.6',
                    backgroundColor: '#F9FAFB',
                    padding: '12px',
                    borderRadius: '6px',
                  }}
                >
                  {selectedDemo.message}
                </div>
              </div>

              {/* Status */}
              <div style={{ marginBottom: '32px' }}>
                <div
                  style={{
                    fontSize: '12px',
                    color: '#6B7280',
                    marginBottom: '8px',
                    textTransform: 'uppercase',
                    letterSpacing: '0.05em',
                  }}
                >
                  Statut Actuel
                </div>
                <span
                  style={{
                    backgroundColor: statusColor(selectedDemo.status),
                    color: 'white',
                    fontSize: '12px',
                    fontWeight: '600',
                    padding: '6px 14px',
                    borderRadius: '999px',
                    display: 'inline-block',
                  }}
                >
                  {statusLabelFr(selectedDemo.status)}
                </span>
              </div>

              {/* Action Buttons */}
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                <button
                  onClick={() => {
                    setToast('Marqué comme contacté');
                    setSelectedDemo(null);
                  }}
                  style={{
                    backgroundColor: '#2D472C',
                    color: 'white',
                    border: 'none',
                    borderRadius: '6px',
                    padding: '12px 16px',
                    fontSize: '14px',
                    fontWeight: '600',
                    cursor: 'pointer',
                    transition: 'all 0.2s ease-out',
                  }}
                  onMouseEnter={(e) => (e.currentTarget.style.opacity = '0.9')}
                  onMouseLeave={(e) => (e.currentTarget.style.opacity = '1')}
                >
                  Marquer comme Contacté
                </button>
                <button
                  onClick={() => {
                    setToast('Démo planifiée');
                    setSelectedDemo(null);
                  }}
                  style={{
                    backgroundColor: '#C5A059',
                    color: 'white',
                    border: 'none',
                    borderRadius: '6px',
                    padding: '12px 16px',
                    fontSize: '14px',
                    fontWeight: '600',
                    cursor: 'pointer',
                    transition: 'all 0.2s ease-out',
                  }}
                  onMouseEnter={(e) => (e.currentTarget.style.opacity = '0.9')}
                  onMouseLeave={(e) => (e.currentTarget.style.opacity = '1')}
                >
                  Planifier une Démo
                </button>
              </div>
            </div>
          </div>
        </>
      )}
    </div>
  );
}

