                          >
                            Email
                          </label>
                          <input
                            type="email"
                            id="email"
                            name="email"
                            required
                            value={formData.email}
                            onChange={handleInputChange}
                            placeholder="votre@email.com"
                            style={{
                              width: '100%',
                              height: '40px',
                              border: '1px solid #E5E7EB',
                              borderRadius: '4px',
                              padding: '0 12px',
                              fontSize: '14px',
                              color: '#333333',
                              fontFamily: 'Inter, sans-serif',
                            }}
                            onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                            onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                          />
                        </div>
                        <div>
                          <label
                            style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }}
                            htmlFor="phone"
                          >
                            Téléphone
                          </label>
                          <input
                            type="tel"
                            id="phone"
                            name="phone"
                            required
                            value={formData.phone}
                            onChange={handleInputChange}
                            placeholder="+216 XX XXX XXX"
                            style={{
                              width: '100%',
                              height: '40px',
                              border: '1px solid #E5E7EB',
                              borderRadius: '4px',
                              padding: '0 12px',
                              fontSize: '14px',
                              color: '#333333',
                              fontFamily: 'Inter, sans-serif',
                            }}
                            onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                            onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                          />
                        </div>
                      </div>

                      {/* Row 4 - City & Student Count */}
                      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '20px' }}>
                        <div>
                          <label
                            style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }}
                            htmlFor="city"
                          >
                            Ville
                          </label>
                          <input
                            type="text"
                            id="city"
                            name="city"
                            required
                            value={formData.city}
                            onChange={handleInputChange}
                            placeholder="Ex: Tunis, Sfax..."
                            style={{
                              width: '100%',
                              height: '40px',
                              border: '1px solid #E5E7EB',
                              borderRadius: '4px',
                              padding: '0 12px',
                              fontSize: '14px',
                              color: '#333333',
                              fontFamily: 'Inter, sans-serif',
                            }}
                            onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                            onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                          />
                        </div>
                        <div>
                          <label
                            style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }}
                            htmlFor="studentCount"
                          >
                            Nombre d'Élèves
                          </label>
                          <select
                            id="studentCount"
                            name="studentCount"
                            required
                            value={formData.studentCount}
                            onChange={handleInputChange}
                            style={{
                              width: '100%',
                              height: '40px',
                              border: '1px solid #E5E7EB',
                              borderRadius: '4px',
                              padding: '0 12px',
                              fontSize: '14px',
                              color: '#333333',
                              fontFamily: 'Inter, sans-serif',
                              backgroundColor: 'white',
                            }}
                            onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                            onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                          >
                            <option value="">Sélectionner...</option>
                            <option value="less-100">Moins de 100 élèves</option>
                            <option value="100-200">100 — 200 élèves</option>
                            <option value="200-400">200 — 400 élèves</option>
                            <option value="400-600">400 — 600 élèves</option>
                            <option value="600+">Plus de 600 élèves</option>
                          </select>
                        </div>
                      </div>

                      {/* Row 5 - Applications Checkboxes */}
                      <div style={{ marginBottom: '20px' }}>
                        <label style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '12px' }}>
                          Applications qui vous intéressent
                        </label>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                          <div
                            onClick={() => handleCheckboxChange('assistant')}
                            style={{
                              border: formData.apps.assistant ? '1px solid #2D472C' : '1px solid #E5E7EB',
                              backgroundColor: formData.apps.assistant ? 'rgba(45, 71, 44, 0.05)' : 'white',
                              borderRadius: '8px',
                              padding: '12px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: '10px',
                              cursor: 'pointer',
                              transition: 'all 0.2s ease-out',
                            }}
                          >
                            <LayoutDashboard size={18} style={{ color: '#2D472C' }} />
                            <span style={{ fontSize: '13px', color: '#333333', flex: 1 }}>Dashboard Assistant</span>
                            {formData.apps.assistant && <CheckCircle size={16} style={{ color: '#2D472C' }} />}
                          </div>

                          <div
                            onClick={() => handleCheckboxChange('teacher')}
                            style={{
                              border: formData.apps.teacher ? '1px solid #2D472C' : '1px solid #E5E7EB',
                              backgroundColor: formData.apps.teacher ? 'rgba(45, 71, 44, 0.05)' : 'white',
                              borderRadius: '8px',
                              padding: '12px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: '10px',
                              cursor: 'pointer',
                              transition: 'all 0.2s ease-out',
                            }}
                          >
                            <GraduationCap size={18} style={{ color: '#2D472C' }} />
                            <span style={{ fontSize: '13px', color: '#333333', flex: 1 }}>App Enseignant</span>
                            {formData.apps.teacher && <CheckCircle size={16} style={{ color: '#2D472C' }} />}
                          </div>

                          <div
                            onClick={() => handleCheckboxChange('parent')}
                            style={{
                              border: formData.apps.parent ? '1px solid #2D472C' : '1px solid #E5E7EB',
                              backgroundColor: formData.apps.parent ? 'rgba(45, 71, 44, 0.05)' : 'white',
                              borderRadius: '8px',
                              padding: '12px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: '10px',
                              cursor: 'pointer',
                              transition: 'all 0.2s ease-out',
                            }}
                          >
                            <Users size={18} style={{ color: '#2D472C' }} />
                            <span style={{ fontSize: '13px', color: '#333333', flex: 1 }}>App Parent</span>
                            {formData.apps.parent && <CheckCircle size={16} style={{ color: '#2D472C' }} />}
                          </div>

                          <div
                            onClick={() => handleCheckboxChange('manager')}
                            style={{
                              border: formData.apps.manager ? '1px solid #2D472C' : '1px solid #E5E7EB',
                              backgroundColor: formData.apps.manager ? 'rgba(45, 71, 44, 0.05)' : 'white',
                              borderRadius: '8px',
                              padding: '12px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: '10px',
                              cursor: 'pointer',
                              transition: 'all 0.2s ease-out',
                            }}
                          >
                            <BarChart2 size={18} style={{ color: '#2D472C' }} />
                            <span style={{ fontSize: '13px', color: '#333333', flex: 1 }}>Dashboard Manager</span>
                            {formData.apps.manager && <CheckCircle size={16} style={{ color: '#2D472C' }} />}
                          </div>
                        </div>
                      </div>

                      {/* Row 6 - Message */}
                      <div style={{ marginBottom: '24px' }}>
                        <label
                          style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }}
                          htmlFor="message"
                        >
                          Message (optionnel)
                        </label>
                        <textarea
                          id="message"
                          name="message"
                          value={formData.message}
                          onChange={handleInputChange}
                          placeholder="Dites-nous en plus sur votre école et vos besoins..."
                          rows={4}
                          style={{
                            width: '100%',
                            border: '1px solid #E5E7EB',
                            borderRadius: '4px',
                            padding: '12px',
                            fontSize: '14px',
                            color: '#333333',
                            fontFamily: 'Inter, sans-serif',
                            resize: 'vertical',
                            minHeight: '100px',
                          }}
                          onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                          onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                        />
                      </div>

                      {/* Submit Button */}
                      <button
                        type="submit"
                        disabled={isSubmitting}
                        style={{
                          width: '100%',
                          height: '48px',
                          backgroundColor: '#2D472C',
                          color: 'white',
                          fontFamily: 'Inter, sans-serif',
                          fontSize: '15px',
                          fontWeight: '600',
                          borderRadius: '4px',
                          border: 'none',
                          cursor: isSubmitting ? 'not-allowed' : 'pointer',
                          opacity: isSubmitting ? 0.75 : 1,
                          transition: 'all 0.2s ease-out',
                        }}
                        onMouseEnter={(e) => {
                          if (!isSubmitting) e.currentTarget.style.opacity = '0.9';
                        }}
                        onMouseLeave={(e) => {
                          if (!isSubmitting) e.currentTarget.style.opacity = '1';
                        }}
                      >
                        {isSubmitting ? 'Envoi en cours…' : 'Envoyer ma Demande de Démo →'}
                      </button>

                      {/* Note */}
                      <div
                        style={{
                          fontSize: '12px',
                          color: '#9CA3AF',
                          textAlign: 'center',
                          marginTop: '12px',
                        }}
                      >
                        ✓ Réponse sous 24h ✓ Démo gratuite ✓ Sans engagement
                      </div>
                    </form>
                  </>
                ) : (
                  /* Success State */
                  <div style={{ textAlign: 'center', padding: '40px 0' }}>
                    <CheckCircle size={64} style={{ color: '#C5A059', margin: '0 auto 24px' }} />
                    <h2
                      style={{
                        fontFamily: 'Montserrat, sans-serif',
                        fontSize: '24px',
                        fontWeight: '700',
                        color: '#333333',
                        marginBottom: '12px',
                      }}
                    >
                      Demande Envoyée!
                    </h2>
                    <p style={{ fontSize: '15px', color: '#6B7280', marginBottom: '32px' }}>
                      Nous vous contacterons dans les 24 heures pour confirmer votre démonstration.
                    </p>
                    <Link to="/">
                      <button
                        style={{
                          padding: '12px 32px',
                          backgroundColor: 'white',
                          color: '#2D472C',
                          border: '1px solid #2D472C',
                          borderRadius: '4px',
                          fontSize: '15px',
                          fontWeight: '600',
                          cursor: 'pointer',
                          transition: 'all 0.2s ease-out',
                        }}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.backgroundColor = '#2D472C';
                          e.currentTarget.style.color = 'white';
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.backgroundColor = 'white';
                          e.currentTarget.style.color = '#2D472C';
                        }}
                      >
                        Retour à l'accueil
                      </button>
                    </Link>
                  </div>
                )}
              </div>
            </motion.div>
          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

import { useEffect, useState } from 'react';
import { motion } from 'motion/react';
import { Navbar } from '../components/Navbar';
import { Footer } from '../components/Footer';
import { Link } from 'react-router';
import pa11 from '../../assets/pa15.png';
import pa1 from '../../assets/pa1.jpg';
import pa2 from '../../assets/pa2.jpg';
import pa3 from '../../assets/pa3.jpg';
import pa4 from '../../assets/pa4.jpg';
import pa5 from '../../assets/pa5.jpg';
import pa6 from '../../assets/pa6.jpg';
import pa7 from '../../assets/pa7.jpg';
import pa8 from '../../assets/pa8.jpg';
import pa9 from '../../assets/pa9.jpg';
import pa10 from '../../assets/pa10.jpg';
import './appHeroMockup.css';

export default function ParentApp() {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollToFeatures = () => {
    const el = document.getElementById('parent-features');
    el?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };


  const screens = [
    { title: 'Calendrier intelligent', image: pa1 },
    { title: 'Profil et paramètres', image: pa2 },
    { title: 'Réservation de réunion et de rendez-vous', image: pa3 },
    { title: 'Signaler une absence', image: pa4 },
    { title: 'Galerie', image: pa5 },
    { title: 'Notifications', image: pa6 },
    { title: 'Finances', image: pa7 },
    { title: 'Contacter l’enseignant', image: pa8 },
    { title: 'Menu', image: pa9 },
    { title: 'Les matières', image: pa10 },
  ];

  const parentFeatures = [
    {
      title: 'Présences Intelligentes',
