:root {
  --omni-hero-bg-1: rgba(45, 71, 44, 0.28);
  --omni-hero-bg-2: rgba(197, 160, 89, 0.28);
  --omni-hero-border: rgba(255, 255, 255, 0.55);
  --omni-hero-shadow: rgba(17, 24, 39, 0.16);
  --omni-hero-inner-border: rgba(229, 231, 235, 0.8);
}

/* Container that holds the image */
.omni-hero-mockup {
  position: relative;
  width: clamp(220px, 28vw, 360px);
}

/* Animated light blob behind the mockup */
.omni-hero-mockup::before {
  content: '';
  position: absolute;
  inset: -22px;
  border-radius: 36px;
  background:
    radial-gradient(closest-side, var(--omni-hero-bg-1) 0%, rgba(45, 71, 44, 0) 62%),
    radial-gradient(closest-side, var(--omni-hero-bg-2) 0%, rgba(197, 160, 89, 0) 58%);
  filter: blur(18px);
  transform: translateZ(0);
  opacity: 0.95;
  animation: omniFloatGlow 7s ease-in-out infinite;
  pointer-events: none;
}

@keyframes omniFloatGlow {
  0% {
    transform: translate3d(0, 0, 0) scale(1);
  }
  50% {
    transform: translate3d(0, -10px, 0) scale(1.03);
  }
  100% {
    transform: translate3d(0, 0, 0) scale(1);
  }
}

/* Glass frame */
.omni-hero-mockup__frame {
  position: relative;
  border-radius: 22px;
  padding: 12px;
  background: linear-gradient(135deg, rgba(255, 255, 255, 0.82), rgba(255, 255, 255, 0.58));
  border: 1px solid var(--omni-hero-border);
  box-shadow:
    0 20px 60px var(--omni-hero-shadow),
    0 1px 0 rgba(255, 255, 255, 0.45) inset;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  outline: 1px solid rgba(197, 160, 89, 0.22);
}

/* subtle gradient ring without mask-composite (more compatible + no CSS diagnostics errors) */
.omni-hero-mockup__frame::after {
  content: '';
  position: absolute;
  inset: 1px;
  border-radius: 21px;
  pointer-events: none;
  box-shadow: 0 0 0 1px rgba(45, 71, 44, 0.18) inset;
  background: linear-gradient(135deg, rgba(197, 160, 89, 0.18), rgba(45, 71, 44, 0.12));
  opacity: 0.55;
  mix-blend-mode: overlay;
}

/* Top bar */
.omni-hero-mockup__bar {
  display: flex;
  align-items: center;
  gap: 10px;
  height: 36px;
  padding: 0 12px;
  border-radius: 14px;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.92), rgba(249, 249, 247, 0.78));
  border: 1px solid var(--omni-hero-inner-border);
  margin-bottom: 10px;
}

.omni-hero-mockup__dots {
  display: inline-flex;
  gap: 7px;
}

.omni-hero-mockup__dot {
  width: 10px;
  height: 10px;
  border-radius: 999px;
  box-shadow: 0 1px 0 rgba(255, 255, 255, 0.45) inset;
}

.omni-hero-mockup__dot--red {
  background: #f87171;
}

.omni-hero-mockup__dot--yellow {
  background: #fbbf24;
}

.omni-hero-mockup__dot--green {
  background: #34d399;
}

.omni-hero-mockup__title {
  margin-left: auto;
  font-size: 11px;
  color: #6b7280;
  letter-spacing: 0.02em;
}

/* Image */
.omni-hero-mockup__img {
  width: 100%;
  height: auto;
  display: block;
  border-radius: 16px;
  border: 1px solid var(--omni-hero-inner-border);
  background: #fff;
  box-shadow:
    0 18px 40px rgba(0, 0, 0, 0.10),
    0 1px 0 rgba(255, 255, 255, 0.55) inset;
  transform: translateZ(0);
  transition: transform 260ms ease, box-shadow 260ms ease;
}

.omni-hero-mockup:hover .omni-hero-mockup__img {
  transform: translate3d(0, -4px, 0) scale(1.01);
  box-shadow:
    0 26px 60px rgba(0, 0, 0, 0.14),
    0 1px 0 rgba(255, 255, 255, 0.55) inset;
}

/* Reduced motion */
@media (prefers-reduced-motion: reduce) {
  .omni-hero-mockup::before {
    animation: none;
  }
  .omni-hero-mockup__img {
    transition: none;
  }
}

