}

/* subtle gradient ring */
.omni-hero-mockup__frame::after {
  content: '';
  position: absolute;
  inset: 1px;
  border-radius: 23px;
  pointer-events: none;
  box-shadow:
    0 0 0 1px rgba(45, 71, 44, 0.18) inset,
    0 0 0 1px rgba(197, 160, 89, 0.14);
  background: linear-gradient(135deg, rgba(197, 160, 89, 0.18), rgba(45, 71, 44, 0.10));
  opacity: 0.55;
  mix-blend-mode: overlay;
}

/* Top bar */
.omni-hero-mockup__bar {
  display: flex;
  align-items: center;
  gap: 10px;
  height: 38px;
  padding: 0 12px;
  border-radius: 14px;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.92), rgba(249, 249, 247, 0.76));
  border: 1px solid rgba(229, 231, 235, 0.92);
  margin-bottom: 12px;
}

.omni-hero-mockup__dots {
  display: inline-flex;
  gap: 7px;
}

.omni-hero-mockup__dot {
  width: 10px;
  height: 10px;
  border-radius: 999px;
  box-shadow: 0 1px 0 rgba(255, 255, 255, 0.45) inset;
}

.omni-hero-mockup__dot--red {
  background: #f87171;
}

.omni-hero-mockup__dot--yellow {
  background: #fbbf24;
}

.omni-hero-mockup__dot--green {
  background: #34d399;
}

.omni-hero-mockup__title {
  margin-left: auto;
  font-size: 11px;
  color: #6b7280;
  letter-spacing: 0.02em;
}

/* Image wrapper enforces same visible dimensions across different images */
.omni-hero-mockup__media {
  width: 100%;
  aspect-ratio: 9 / 16;
  border-radius: 18px;
  overflow: hidden;
  border: 1px solid rgba(229, 231, 235, 0.90);
  background: #fff;
  box-shadow:
    0 18px 40px rgba(0, 0, 0, 0.10),
    0 1px 0 rgba(255, 255, 255, 0.55) inset;
}

/* Image */
.omni-hero-mockup__img {
  width: 100%;
  height: 100%;
  display: block;
  object-fit: cover;
  transform: translateZ(0);
  transition: transform 260ms ease;
}

.omni-hero-mockup:hover .omni-hero-mockup__img {
  transform: scale(1.02);
}

/* Reduced motion */
@media (prefers-reduced-motion: reduce) {
  .omni-hero-mockup::before {
    animation: none;
  }
  .omni-hero-mockup__img {
    transition: none;
  }
}

// Ensure TypeScript can resolve packages that ship .d.mts typings under some TS setups.
declare module '@tailwindcss/vite' {
  const plugin: any
  export default plugin
}
